import React, { useState, useEffect } from 'react';
import { useLocation, useParams, useNavigate } from 'react-router-dom';

const StudySession = ({ markDayComplete }) => {
  const { day } = useParams();
  const { state } = useLocation();
  const navigate = useNavigate();

  // 1. SETTING THE TIME (e.g., 45 minutes = 2700 seconds)
  const SESSION_DURATION = 2700; 
  const MINIMUM_REQUIRED_TIME = 600; // Must study at least 10 mins (600s) before completing

  const [timeLeft, setTimeLeft] = useState(SESSION_DURATION);
  const [isActive, setIsActive] = useState(false);
  const [showAIField, setShowAIField] = useState(false);
  const [userAnswer, setUserAnswer] = useState('');
  const [errorMessage, setErrorMessage] = useState('');

  useEffect(() => {
    let interval = null;
    if (isActive && timeLeft > 0) {
      interval = setInterval(() => setTimeLeft(t => t - 1), 1000);
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft]);

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}m ${secs < 10 ? '0' : ''}${secs}s`;
  };

  const handleAttemptComplete = () => {
    const timeSpent = SESSION_DURATION - timeLeft;

    // 2. STRICTOR CHECK: Prevent skipping
    if (timeSpent < MINIMUM_REQUIRED_TIME) {
      setErrorMessage(`⚠️ You've only studied for ${Math.floor(timeSpent/60)} minutes. You must focus for at least 10 minutes before marking this as complete!`);
      
      // Clear error message after 5 seconds
      setTimeout(() => setErrorMessage(''), 5000);
      return;
    }

    // If they passed the time check, show the AI quiz
    setIsActive(false);
    setShowAIField(true);
  };

  const submitToAI = () => {
    if (userAnswer.length < 30) {
      alert("Your explanation is too brief. Provide more detail to prove you practiced!");
      return;
    }
    markDayComplete(day);
    navigate('/dashboard');
  };

  return (
    <div style={{ padding: '30px', fontFamily: 'Arial', textAlign: 'center', backgroundColor: '#fdfdfd', minHeight: '100vh' }}>
      <div style={{ maxWidth: '650px', margin: '0 auto', background: 'white', padding: '30px', borderRadius: '15px', boxShadow: '0 8px 20px rgba(0,0,0,0.08)' }}>
        
        <h2 style={{ color: '#2c3e50' }}>Topic: {state?.topic}</h2>
        <p style={{ color: '#7f8c8d' }}>Deep Focus Session: 45 Minutes</p>

        {/* Timer UI */}
        <div style={{ fontSize: '60px', margin: '30px 0', fontWeight: 'bold', color: isActive ? '#2980b9' : '#95a5a6' }}>
          {formatTime(timeLeft)}
        </div>

        {/* Error Message for Cheating */}
        {errorMessage && (
          <div style={{ color: '#e74c3c', backgroundColor: '#fdeaea', padding: '10px', borderRadius: '5px', marginBottom: '20px', fontWeight: 'bold' }}>
            {errorMessage}
          </div>
        )}

        {!showAIField ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
            <button 
              onClick={() => setIsActive(!isActive)} 
              style={{ padding: '15px', fontSize: '18px', cursor: 'pointer', backgroundColor: isActive ? '#f39c12' : '#27ae60', color: 'white', border: 'none', borderRadius: '8px' }}>
              {isActive ? '⏸ Pause Focus' : '▶ Start Study Timer'}
            </button>

            <button 
              onClick={handleAttemptComplete}
              style={{ padding: '15px', fontSize: '16px', cursor: 'pointer', backgroundColor: '#34495e', color: 'white', border: 'none', borderRadius: '8px' }}>
              Done for Today? (Verify Learning)
            </button>
          </div>
        ) : (
          <div style={{ textAlign: 'left', marginTop: '20px' }}>
            <div style={{ padding: '15px', backgroundColor: '#f0f7ff', borderRadius: '8px', borderLeft: '4px solid #3498db', marginBottom: '15px' }}>
              <strong>AI Review:</strong> How did your practice go? Describe one specific challenge you faced while learning <strong>{state?.topic}</strong> and how you solved it.
            </div>
            <textarea 
              placeholder="Write your brief summary here..."
              value={userAnswer}
              onChange={(e) => setUserAnswer(e.target.value)}
              style={{ width: '100%', height: '120px', borderRadius: '8px', padding: '10px' }}
            />
            <button onClick={submitToAI} style={{ width: '100%', marginTop: '15px', padding: '15px', backgroundColor: '#2c3e50', color: 'white', borderRadius: '8px', cursor: 'pointer' }}>
              Submit Progress
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default StudySession;
